func init() {
	f := func(d *deps.Deps) *internal.TemplateFuncsNamespace {
		ctx, err := New(d)
		if err != nil {

			panic(err)
		}

		ns := &internal.TemplateFuncsNamespace{
			Name:		name,
			Context:	func(cctx context.Context, args ...any) (any, error) { return ctx, nil },
			OnCreated: func(m map[string]any) {
				for _, v := range m {
					switch v := v.(type) {
					case *css.Namespace:
						ctx.cssNs = v
					case *js.Namespace:
						ctx.jsNs = v
					}
				}
				if ctx.cssNs == nil {
					panic("css namespace not found")
				}
				if ctx.jsNs == nil {
					panic("js namespace not found")
				}
			},
		}

		ns.AddMethodMapping(ctx.Get,
			nil,
			[][2]string{},
		)

		ns.AddMethodMapping(ctx.GetRemote,
			nil,
			[][2]string{},
		)

		ns.AddMethodMapping(ctx.Fingerprint,
			[]string{"fingerprint"},
			[][2]string{},
		)

		ns.AddMethodMapping(ctx.Minify,
			[]string{"minify"},
			[][2]string{},
		)

		return ns
	}

	internal.AddTemplateFuncsNamespace(f)
}
